<span class="line"><span style="color:#FFCB6B;">service/tekton-dashboard</span><span style="color:#A6ACCD;">              </span><span style="color:#C3E88D;">NodePort</span><span style="color:#A6ACCD;">    </span><span style="color:#C3E88D;">10.97.2.217</span><span style="color:#A6ACCD;">     </span><span style="color:#89DDFF;">&lt;</span><span style="color:#C3E88D;">non</span><span style="color:#A6ACCD;">e</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">        </span><span style="color:#F78C6C;">9097</span><span style="color:#C3E88D;">:</span><span style="color:#F78C6C;">31805</span><span style="color:#C3E88D;">/TCP</span><span style="color:#A6ACCD;">                       </span><span style="color:#C3E88D;">81d</span></span>
